#include <iostream>
#include <string>

class Animal
{
public:
    virtual std::string speak() const
    {
        return "Animal says: ...";
    }
};

class Cat : public Animal
{
public:
    std::string speak() const override
    {
        return "Cat says: Meow";
    }
};

int main()
{
    int n{};
    std::cin >> n;

    Animal* animals[3]{nullptr, nullptr, nullptr};

    for (int i{0}; i < n; ++i)
    {
        animals[i] = new Cat{};
    }

    for (int i{0}; i < n; ++i)
    {
        std::cout << animals[i]->speak() << '\n';
    }

    Animal base{};
    std::cout << base.speak() << '\n';

    for (int i{0}; i < n; ++i)
    {
        delete animals[i];
    }

    return 0;
}

