exercises.solution_code:
#include <iostream>
#include <sstream>
#include <iomanip>
#include <string>

class Shape
{
public:
    virtual Shape* clone() const { return new Shape{*this}; }
    virtual std::string describe() const { return "Shape"; }
};

class Circle : public Shape
{
    double m_radius{};

public:
    Circle(double radius) : m_radius{radius} {}

    Circle* clone() const override final
    {
        return new Circle{*this};
    }

    std::string describe() const override
    {
        std::ostringstream oss{};
        oss << "Circle r=" << std::fixed << std::setprecision(1) << m_radius;
        return oss.str();
    }
};

class Square : public Shape
{
    double m_side{};

public:
    Square(double side) : m_side{side} {}

    Square* clone() const override
    {
        return new Square{*this};
    }

    std::string describe() const override
    {
        std::ostringstream oss{};
        oss << "Square s=" << std::fixed << std::setprecision(1) << m_side;
        return oss.str();
    }
};

int main()
{
    std::string type{};
    double value{};
    std::cin >> type >> value;

    Shape* original{nullptr};

    if (type == "circle")
        original = new Circle{value};
    else
        original = new Square{value};

    std::cout << original->describe() << '\n';

    Shape* cloned{original->clone()};
    std::cout << cloned->describe() << '\n';

    delete cloned;
    delete original;

    return 0;
}
